import { BASE_URL } from "../constants"
import { BusinessUnitEntity } from "../entities/BusinessUnitEntity"
import FetchUtils from "../utils/fetch"

interface AddBusinessUnitData {
    business_unit: string
    business_unit_warn: number
    business_unit_alarm: number
}

interface UpdateBusinessUnitData {
    business_unit?: string
    business_unit_warn?: number
    business_unit_alarm?: number
}

class BusinessUnitService {
    static async GetAllBusinessUnit(): Promise<BusinessUnitEntity[]> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/business_unit`)

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        const rawData = Array.isArray(resp.data) ? resp.data : []
        const data: BusinessUnitEntity[] = []

        for (let i = 0; i < rawData.length; i++) {
            data.push({
                business_unit_id: rawData[i].business_unit_id,
                business_unit: rawData[i].business_unit,
                business_unit_warn: rawData[i].business_unit_warn,
                business_unit_alarm: rawData[i].business_unit_alarm,
            })
        }

        return data
    }

    static async AddBusinessUnit(data: AddBusinessUnitData): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/business_unit`,
            {
                method: 'POST',
                body: JSON.stringify({ ...data }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }

    static async UpdateBusinessUnit(business_unit_id: number, fields: UpdateBusinessUnitData): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/business_unit`,
            {
                method: 'PATCH',
                body: JSON.stringify({ business_unit_id: business_unit_id, fields }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }

    static async DeleteBusinessUnit(business_unit_id: number): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/business_unit`,
            {
                method: 'DELETE',
                body: JSON.stringify({ business_unit_id: business_unit_id }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }
}

export { BusinessUnitService }